.masonry {
  columns: 3;
  column-gap: 1rem;
}

.masonry-item {
  break-inside: avoid;
  margin-bottom: 1rem;
}

/* Alternative with Grid (when masonry value is supported):
.masonry {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-template-rows: masonry;
  gap: 1rem;
} */

.layout {
  display: grid;
  grid-template-columns: 250px 1fr;
  min-height: 100vh;
}

.sidebar {
  position: sticky;
  top: 0;
  height: 100vh;
  overflow-y: auto;
  background: #f8f9fa;
}

@media (max-width: 768px) {
  .layout {
    grid-template-columns: 1fr;
  }
  .sidebar {
    position: fixed;
    left: -250px;
    width: 250px;
    z-index: 1000;
    transition: left 0.3s ease;
  }
  .sidebar.open { left: 0; }
}

details {
  border: 1px solid #ddd;
  border-radius: 4px;
  margin-bottom: 0.5rem;
}

summary {
  padding: 1rem;
  cursor: pointer;
  font-weight: 600;
  background: #f8f9fa;
}

summary:hover { background: #e9ecef; }

details[open] summary {
  border-bottom: 1px solid #ddd;
}

details > :not(summary) {
  padding: 1rem;
}

.gradient-border {
  position: relative;
  background: #fff;
  border-radius: 8px;
  padding: 1.5rem;
}

.gradient-border::before {
  content: '';
  position: absolute;
  inset: -2px;
  border-radius: 10px;
  background: linear-gradient(135deg, #667eea, #764ba2);
  z-index: -1;
}

/* Alternative with border-image:
.gradient-border {
  border: 2px solid;
  border-image: linear-gradient(135deg, #667eea, #764ba2) 1;
} */

.skeleton {
  background: #e0e0e0;
  border-radius: 4px;
  position: relative;
  overflow: hidden;
}

.skeleton::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.4), transparent);
  animation: shimmer 1.5s infinite;
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

.skeleton-title { height: 1.5rem; width: 60%; margin-bottom: 1rem; }
.skeleton-text { height: 1rem; width: 100%; margin-bottom: 0.5rem; }
.skeleton-avatar { width: 50px; height: 50px; border-radius: 50%; }
